function findSkillByName(skillName) {
  const manager = getSkillManager();
  const allSkills = manager.getAllSkills();
  const normalizedName = skillName.startsWith("/") ? skillName.slice(1) : skillName;
  let skill = allSkills.find((s) => s.definition.id === normalizedName);
  if (skill)
    return skill.definition;
  skill = allSkills.find((s) => s.definition.name.toLowerCase() === normalizedName.toLowerCase());
  if (skill)
    return skill.definition;
  const aliases = {
    review: "code-review",
    "code-review": "code-review",
    git: "git-helper",
    "git-helper": "git-helper",
    test: "test-generator",
    "test-generator": "test-generator",
    doc: "doc-generator",
    "doc-generator": "doc-generator",
    remember: "remember",
    verify: "verify",
    simplify: "simplify",
    stuck: "stuck",
    batch: "batch",
    keybindings: "keybindings"
  };
  const aliasedId = aliases[normalizedName.toLowerCase()];
  if (aliasedId) {
    skill = allSkills.find((s) => s.definition.id === aliasedId);
    if (skill)
      return skill.definition;
  }
  return;
}
