init_zod();
var bughunterInputSchema = exports_external.object({
  action: exports_external.enum(["scan", "patterns", "fix", "report"]).optional().default("scan").describe("Bughunter action"),
  target: exports_external.string().optional().describe("Target directory or file to scan"),
  severity: exports_external.enum(["low", "medium", "high", "critical"]).optional().describe("Filter by severity")
});
var BUG_PATTERNS = [
  {
    id: "TODO",
    name: "TODO Comments",
    pattern: /\/\/\s*TODO|\/\/\s*FIXME|\/\/\s*HACK/,
    severity: "low",
    message: "Unresolved TODO/FIXME/HACK comment found",
    suggestion: "Address the TODO or create a tracking issue"
  },
  {
    id: "CONSOLE_LOG",
    name: "Console Log Statements",
    pattern: /console\.(log|debug|info)/,
    severity: "medium",
    message: "Console log statement in production code",
    suggestion: "Remove or replace with proper logging"
  },
  {
    id: "EMPTY_CATCH",
    name: "Empty Catch Block",
    pattern: /catch\s*\([^)]*\)\s*{\s*}/,
    severity: "high",
    message: "Empty catch block that silently ignores errors",
    suggestion: "Add error handling or logging"
  },
  {
    id: "TYPECAST_ANY",
    name: "Type Casting to any",
    pattern: /as\s+any|\<\s*any\s*\>|:\s*any\s*[=;]/,
    severity: "medium",
    message: "TypeScript type cast to any",
    suggestion: "Use proper type annotations"
  },
  {
    id: "HARD_CODED_SECRET",
    name: "Hardcoded Secret",
    pattern: /(password|secret|api_key|apikey|token)\s*[:=]\s*['"][^'"]+['"]/i,
    severity: "critical",
    message: "Potential hardcoded secret or credential",
    suggestion: "Move to environment variables or config"
  },
  {
    id: "SQL_INJECTION",
    name: "Potential SQL Injection",
    pattern: /query\s*\(\s*`.*\$\{/,
    severity: "critical",
    message: "Potential SQL injection vulnerability",
    suggestion: "Use parameterized queries"
  },
  {
    id: "XSS",
    name: "Potential XSS",
    pattern: /innerHTML\s*=|dangerouslySetInnerHTML/,
    severity: "high",
    message: "Potential XSS vulnerability",
    suggestion: "Sanitize user input before rendering"
  },
  {
    id: "SYNC_AWAIT",
    name: "Sync/Await Mismatch",
    pattern: /await\s+[^;]*;\s*$/m,
    severity: "low",
    message: "Potential sync/await mismatch",
    suggestion: "Ensure async functions are properly awaited"
  }
];
async function scanFile(filePath, patterns) {
  const bugs = [];
  try {
    const fs3 = await import("fs");
    const content = fs3.readFileSync(filePath, "utf-8");
    const lines = content.split(`
`);
    for (const pattern of patterns) {
      const regex2 = new RegExp(pattern.pattern.source, pattern.pattern.flags);
      for (let i = 0;i < lines.length; i++) {
        if (regex2.test(lines[i])) {
          bugs.push({
            id: pattern.id,
            name: pattern.name,
            severity: pattern.severity,
            file: filePath,
            line: i + 1,
            message: pattern.message,
            suggestion: pattern.suggestion,
            code: lines[i].trim()
          });
        }
      }
    }
  } catch {}
  return bugs;
}
async function scanDirectory(dir, patterns) {
  const bugs = [];
  let filesScanned = 0;
  try {
    const fs3 = await import("fs");
    const path19 = await import("path");
    const entries = fs3.readdirSync(dir, { withFileTypes: true });
    for (const entry of entries) {
      const fullPath = path19.join(dir, entry.name);
      if (entry.isDirectory()) {
        if (!entry.name.startsWith(".") && entry.name !== "node_modules") {
          const result2 = await scanDirectory(fullPath, patterns);
          bugs.push(...result2.bugs);
          filesScanned += result2.filesScanned;
        }
      } else if (entry.isFile() && /\.(ts|tsx|js|jsx)$/.test(entry.name)) {
        const fileBugs = await scanFile(fullPath, patterns);
        bugs.push(...fileBugs);
        filesScanned++;
      }
    }
  } catch {}
  return { bugs, filesScanned };
}
async function executeBughunterCommand(input) {
  const { action = "scan", target, severity } = input;
  switch (action) {
    case "patterns": {
      return {
        success: true,
        message: `
Bug Hunter Patterns
===================

Available patterns:

${BUG_PATTERNS.map((p) => {
          const icon = p.severity === "critical" ? "\uD83D\uDD34" : p.severity === "high" ? "\uD83D\uDFE0" : p.severity === "medium" ? "\uD83D\uDFE1" : "\uD83D\uDFE2";
          return `${icon} ${p.id.padEnd(15)} [${p.severity.padEnd(8)}] ${p.name}`;
        }).join(`
`)}

Use /bughunter scan to run the detector.
`
      };
    }
    case "scan": {
      const scanPath = target || process.cwd();
      const patterns = severity ? BUG_PATTERNS.filter((p) => p.severity === severity) : BUG_PATTERNS;
      const result2 = await scanDirectory(scanPath, patterns);
      const bySeverity = { critical: 0, high: 0, medium: 0, low: 0 };
      for (const bug of result2.bugs) {
        bySeverity[bug.severity]++;
      }
      const sortedBugs = result2.bugs.sort((a, b) => {
        const order = { critical: 0, high: 1, medium: 2, low: 3 };
        return order[a.severity] - order[b.severity];
      });
      const bugList = sortedBugs.slice(0, 20).map((bug) => {
        const icon = bug.severity === "critical" ? "\uD83D\uDD34" : bug.severity === "high" ? "\uD83D\uDFE0" : bug.severity === "medium" ? "\uD83D\uDFE1" : "\uD83D\uDFE2";
        return `${icon} ${bug.file}:${bug.line}
  ${bug.name} (${bug.severity})
  ${bug.code ? `  \`${bug.code.slice(0, 60)}...\`` : ""}`;
      }).join(`

`);
      return {
        success: true,
        message: `
Bug Hunter Scan Results
=======================

Scanned: ${result2.filesScanned} files
Found:   ${result2.bugs.length} issues

By Severity:
  \uD83D\uDD34 Critical: ${bySeverity.critical}
  \uD83D\uDFE0 High:     ${bySeverity.high}
  \uD83D\uDFE1 Medium:   ${bySeverity.medium}
  \uD83D\uDFE2 Low:      ${bySeverity.low}

${bugList || "No bugs found!"}

${result2.bugs.length > 20 ? `
... and ${result2.bugs.length - 20} more issues` : ""}
`,
        bugs: sortedBugs,
        stats: {
          filesScanned: result2.filesScanned,
          issuesFound: result2.bugs.length,
          bySeverity
        }
      };
    }
    case "report": {
      return {
        success: true,
        message: `
Bug Hunter Report
=================

Run /bughunter scan to detect issues.

Use /bughunter patterns to see available detection patterns.
Use /bughunter scan severity=high to filter by severity.
`
      };
    }
    default:
      return {
        success: false,
        message: `Unknown action: ${action}

Available: scan, patterns, report`
      };
  }
}

