// src/services/cache/cacheService.ts
import { createHash } from "crypto";
import { readFile as readFile12, writeFile as writeFile7, mkdir as mkdir6, rm as rm2, readdir as readdir5 } from "fs/promises";
import { join as join10 } from "path";
import { homedir as homedir2 } from "os";
var DEFAULT_TTL = 5 * 60 * 1000;
var DEFAULT_MAX_SIZE = 100 * 1024 * 1024;

class CacheService {
  memoryCache = new Map;
  stats = { hits: 0, misses: 0, size: 0, entries: 0 };
  ttl;
  maxSize;
  cacheDir;
  constructor(options = {}) {
    this.ttl = options.ttl ?? DEFAULT_TTL;
    this.maxSize = options.maxSize ?? DEFAULT_MAX_SIZE;
    this.cacheDir = options.directory ?? join10(homedir2(), ".qoocode", "cache");
  }
  generateKey(toolName, input) {
    const data = JSON.stringify({ tool: toolName, input });
    return createHash("sha256").update(data).digest("hex").slice(0, 32);
  }
  async get(key) {
    const memEntry = this.memoryCache.get(key);
    if (memEntry) {
      if (this.isExpired(memEntry)) {
        this.memoryCache.delete(key);
      } else {
        this.stats.hits++;
        return memEntry.value;
      }
    }
    try {
      const filePath = this.getCacheFilePath(key);
      const content = await readFile12(filePath, "utf-8");
      const entry = JSON.parse(content);
      if (this.isExpired(entry)) {
        await this.delete(key);
        this.stats.misses++;
        return null;
      }
      this.stats.hits++;
      this.memoryCache.set(key, entry);
      return entry.value;
    } catch {
      this.stats.misses++;
      return null;
    }
  }
  async set(key, value, ttl) {
    const now2 = Date.now();
    const entry = {
      key,
      value,
      createdAt: now2,
      expiresAt: ttl ? now2 + ttl : this.ttl ? now2 + this.ttl : null,
      size: Buffer.byteLength(JSON.stringify(value), "utf-8")
    };
    this.memoryCache.set(key, entry);
    this.updateStats();
    try {
      await mkdir6(this.cacheDir, { recursive: true });
      const filePath = this.getCacheFilePath(key);
      await writeFile7(filePath, JSON.stringify(entry), "utf-8");
    } catch (error) {
      console.error("Failed to write cache to disk:", error);
    }
    await this.enforceMaxSize();
  }
  async delete(key) {
    this.memoryCache.delete(key);
    try {
      const filePath = this.getCacheFilePath(key);
      await rm2(filePath, { force: true });
    } catch {}
  }
  async clear() {
    this.memoryCache.clear();
    this.stats = { hits: 0, misses: 0, size: 0, entries: 0 };
    try {
      const files = await readdir5(this.cacheDir);
      await Promise.all(files.map((file) => rm2(join10(this.cacheDir, file), { force: true })));
    } catch {}
  }
  getStats() {
    return { ...this.stats, entries: this.memoryCache.size };
  }
  async getSize() {
    try {
      const files = await readdir5(this.cacheDir);
      let totalSize = 0;
      for (const file of files) {
        const stat5 = await Bun.file(join10(this.cacheDir, file)).stat();
        totalSize += stat5.size;
      }
      return totalSize;
    } catch {
      return 0;
    }
  }
  isExpired(entry) {
    return entry.expiresAt !== null && Date.now() > entry.expiresAt;
  }
  getCacheFilePath(key) {
    return join10(this.cacheDir, `${key}.json`);
  }
  updateStats() {
    let totalSize = 0;
    for (const entry of this.memoryCache.values()) {
      totalSize += entry.size;
    }
    this.stats.size = totalSize;
    this.stats.entries = this.memoryCache.size;
  }
  async enforceMaxSize() {
    if (this.stats.size <= this.maxSize)
      return;
    const entries = Array.from(this.memoryCache.entries()).sort((a, b) => a[1].createdAt - b[1].createdAt);
    let freedSize = 0;
    const targetSize = this.maxSize * 0.8;
    for (const [key, entry] of entries) {
      if (this.stats.size - freedSize <= targetSize)
        break;
      freedSize += entry.size;
      await this.delete(key);
    }
  }
}
var cacheService = new CacheService;
async function clearAllCaches() {
  await cacheService.clear();
}
function getCacheStats2() {
  return cacheService.getStats();
}

// src/services/storage/toolResultStorage.ts
import { readFile as readFile13, writeFile as writeFile8, mkdir as mkdir7, rm as rm3, readdir as readdir6 } from "fs/promises";
import { join as join11, dirname as dirname2 } from "path";
import { homedir as homedir3 } from "os";
var STORAGE_DIR = join11(homedir3(), ".qoocode", "tool-results");

class ToolResultStorage {
  initialized = false;
  async initialize() {
    if (this.initialized)
      return;
    await mkdir7(STORAGE_DIR, { recursive: true });
    this.initialized = true;
  }
  generateId() {
    return `tool_${Date.now()}_${Math.random().toString(36).slice(2, 9)}`;
  }
  getFilePath(id) {
    const prefix = id.slice(5, 13);
    return join11(STORAGE_DIR, prefix, `${id}.json`);
  }
  async save(result2) {
    await this.initialize();
    const id = this.generateId();
    const record2 = {
      id,
      ...result2
    };
    const filePath = this.getFilePath(id);
    await mkdir7(dirname2(filePath), { recursive: true });
    await writeFile8(filePath, JSON.stringify(record2, null, 2), "utf-8");
    return record2;
  }
  async get(id) {
    await this.initialize();
    try {
      const filePath = this.getFilePath(id);
      const content = await readFile13(filePath, "utf-8");
      return JSON.parse(content);
    } catch {
      return null;
    }
  }
  async query(query2 = {}) {
    await this.initialize();
    const results = [];
    const { toolName, sessionId, startTime, endTime, limit: limit2 = 100, offset = 0 } = query2;
    try {
      const subdirs = await readdir6(STORAGE_DIR);
      for (const subdir of subdirs) {
        const subdirPath = join11(STORAGE_DIR, subdir);
        try {
          const files = await readdir6(subdirPath);
          for (const file of files) {
            if (!file.endsWith(".json"))
              continue;
            const filePath = join11(subdirPath, file);
            const content = await readFile13(filePath, "utf-8");
            const record2 = JSON.parse(content);
            if (toolName && record2.toolName !== toolName)
              continue;
            if (sessionId && record2.sessionId !== sessionId)
              continue;
            if (startTime && record2.timestamp < startTime)
              continue;
            if (endTime && record2.timestamp > endTime)
              continue;
            results.push(record2);
          }
        } catch {}
      }
      results.sort((a, b) => b.timestamp - a.timestamp);
      return results.slice(offset, offset + limit2);
    } catch {
      return [];
    }
  }
  async delete(id) {
    await this.initialize();
    try {
      const filePath = this.getFilePath(id);
      await rm3(filePath, { force: true });
      return true;
    } catch {
      return false;
    }
  }
  async deleteBySession(sessionId) {
    await this.initialize();
    let deletedCount = 0;
    const results = await this.query({ sessionId, limit: 1e4 });
    for (const result2 of results) {
      if (result2.sessionId === sessionId) {
        await this.delete(result2.id);
        deletedCount++;
      }
    }
    return deletedCount;
  }
  async cleanup(maxAge = 7 * 24 * 60 * 60 * 1000) {
    await this.initialize();
    const cutoff = Date.now() - maxAge;
    let deletedCount = 0;
    try {
      const subdirs = await readdir6(STORAGE_DIR);
      for (const subdir of subdirs) {
        const subdirPath = join11(STORAGE_DIR, subdir);
        try {
          const files = await readdir6(subdirPath);
          for (const file of files) {
            if (!file.endsWith(".json"))
              continue;
            const filePath = join11(subdirPath, file);
            const stat6 = await Bun.file(filePath).stat();
            if (stat6.mtimeMs < cutoff) {
              await rm3(filePath, { force: true });
              deletedCount++;
            }
          }
        } catch {}
      }
    } catch {}
    return deletedCount;
  }
  async getStats() {
    await this.initialize();
    const stats = {
      totalResults: 0,
      totalSize: 0,
      byTool: {}
    };
    try {
      const subdirs = await readdir6(STORAGE_DIR);
      for (const subdir of subdirs) {
        const subdirPath = join11(STORAGE_DIR, subdir);
        try {
          const files = await readdir6(subdirPath);
          for (const file of files) {
            if (!file.endsWith(".json"))
              continue;
            const filePath = join11(subdirPath, file);
            const fileStat = await Bun.file(filePath).stat();
            stats.totalSize += fileStat.size;
            try {
              const content = await readFile13(filePath, "utf-8");
              const record2 = JSON.parse(content);
              stats.totalResults++;
              stats.byTool[record2.toolName] = (stats.byTool[record2.toolName] || 0) + 1;
              if (!stats.oldestTimestamp || record2.timestamp < stats.oldestTimestamp) {
                stats.oldestTimestamp = record2.timestamp;
              }
              if (!stats.newestTimestamp || record2.timestamp > stats.newestTimestamp) {
                stats.newestTimestamp = record2.timestamp;
              }
            } catch {}
          }
        } catch {}
      }
    } catch {}
    return stats;
  }
  async clear() {
    await this.initialize();
    try {
      const subdirs = await readdir6(STORAGE_DIR);
      for (const subdir of subdirs) {
        const subdirPath = join11(STORAGE_DIR, subdir);
        await rm3(subdirPath, { recursive: true, force: true });
      }
    } catch {}
  }
}
var toolResultStorage = new ToolResultStorage;

// src/commands/cache/cache.ts
var cacheCmd = {
  name: "cache",
  aliases: ["cached"],
  description: "Manage tool result cache",
  type: "local",
  async execute(args) {
    const parts = args.trim().split(/\s+/);
    const action = parts[0]?.toLowerCase() || "info";
    if (action === "info" || action === "status") {
      const stats = getCacheStats2();
      const storageStats = await toolResultStorage.getStats();
      const lines = [
        "\uD83D\uDCE6 Cache Status",
        "================",
        "",
        "Tool Result Cache:",
        `  Entries: ${stats.entries}`,
        `  Hits: ${stats.hits}`,
        `  Misses: ${stats.misses}`,
        `  Hit Rate: ${stats.hits + stats.misses > 0 ? (stats.hits / (stats.hits + stats.misses) * 100).toFixed(1) : 0}%`,
        `  Memory Size: ${formatBytes(stats.size)}`,
        "",
        "Tool Result Storage:",
        `  Total Results: ${storageStats.totalResults}`,
        `  Disk Size: ${formatBytes(storageStats.totalSize)}`,
        ""
      ];
      if (Object.keys(storageStats.byTool).length > 0) {
        lines.push("Results by Tool:");
        for (const [tool, count] of Object.entries(storageStats.byTool)) {
          lines.push(`  ${tool}: ${count}`);
        }
      }
      return lines.join(`
`);
    }
    if (action === "clear" || action === "clean") {
      await clearAllCaches();
      return `\u2705 Tool result cache cleared.

Use /cache info to verify.`;
    }
    if (action === "clear-storage" || action === "clear-results") {
      const deleted = await toolResultStorage.cleanup(0);
      return `\u2705 Cleaned up ${deleted} tool result records.`;
    }
    if (action === "cleanup" || action === "gc") {
      const deleted = await toolResultStorage.cleanup();
      return `\u2705 Cleaned up ${deleted} expired tool result records.`;
    }
    return `\uD83D\uDCE6 Cache Commands
==================

Usage: /cache <command>

Commands:
  /cache info          - Show cache statistics
  /cache clear         - Clear tool result cache
  /cache cleanup       - Remove expired results (older than 7 days)
  /cache clear-storage - Remove all stored tool results

Examples:
  /cache info          - View cache usage
  /cache clear         - Free up memory cache
  /cache cleanup       - Free up disk space`;
  }
};
function formatBytes(bytes) {
  if (bytes === 0)
    return "0 B";
  const k = 1024;
  const sizes = ["B", "KB", "MB", "GB"];
  const i = Math.floor(Math.log(bytes) / Math.log(k));
  return `${parseFloat((bytes / Math.pow(k, i)).toFixed(1))} ${sizes[i]}`;
}

// src/services/updater/updaterService.ts
import { exec as exec10 } from "child_process";
import { promisify as promisify9 } from "util";
import { homedir as homedir4 } from "os";
import { access } from "fs/promises";
import { constants as fsConstants } from "fs";
var execAsync9 = promisify9(exec10);
var CURRENT_VERSION = "0.1.21";
var PACKAGE_NAME = "qoocode";
async function checkGlobalInstallPermissions() {
  try {
    const prefixResult = await execAsync9("npm -g config get prefix", { cwd: homedir4() });
    const prefix = prefixResult.stdout.trim();
    try {
      await access(prefix, fsConstants.W_OK);
      return { hasPermissions: true, npmPrefix: prefix };
    } catch {
      return { hasPermissions: false, npmPrefix: prefix };
    }
  } catch (error) {
    return { hasPermissions: false, npmPrefix: null };
  }
}
async function getLatestVersion() {
  try {
    const result2 = await execAsync9(`npm view ${PACKAGE_NAME}@latest version --prefer-online`, { cwd: homedir4() });
    return result2.stdout.trim();
  } catch (error) {
    console.error("\u83B7\u53D6\u6700\u65B0\u7248\u672C\u5931\u8D25:", error);
    return null;
  }
}
async function getVersionHistory(limit2 = 10) {
  try {
    const result2 = await execAsync9(`npm view ${PACKAGE_NAME} versions --json --prefer-online`, { cwd: homedir4() });
    const versions = JSON.parse(result2.stdout.trim());
    return versions.slice(-limit2).reverse();
  } catch (error) {
    console.error("\u83B7\u53D6\u7248\u672C\u5386\u53F2\u5931\u8D25:", error);
    return [];
  }
}
function compareVersions(v1, v2) {
  const parts1 = v1.replace(/[^\d.]/g, "").split(".").map(Number);
  const parts2 = v2.replace(/[^\d.]/g, "").split(".").map(Number);
  for (let i = 0;i < Math.max(parts1.length, parts2.length); i++) {
    const p1 = parts1[i] || 0;
    const p2 = parts2[i] || 0;
    if (p1 > p2)
      return 1;
    if (p1 < p2)
      return -1;
  }
  return 0;
}
async function checkForUpdates() {
  const currentVersion = CURRENT_VERSION;
  const latestVersion = await getLatestVersion();
  if (!latestVersion) {
    return {
      hasUpdate: false,
      currentVersion,
      latestVersion: null,
      message: "\u65E0\u6CD5\u68C0\u67E5\u66F4\u65B0\uFF0C\u8BF7\u7A0D\u540E\u91CD\u8BD5"
    };
  }
  const hasUpdate = compareVersions(latestVersion, currentVersion) > 0;
  return {
    hasUpdate,
    currentVersion,
    latestVersion,
    message: hasUpdate ? `\u53D1\u73B0\u65B0\u7248\u672C: ${latestVersion} (\u5F53\u524D: ${currentVersion})` : `\u5DF2\u662F\u6700\u65B0\u7248\u672C (${currentVersion})`
  };
}
async function installGlobalPackage(specificVersion) {
  const { hasPermissions } = await checkGlobalInstallPermissions();
  if (!hasPermissions) {
    return "no_permissions";
  }
  try {
    const packageSpec = specificVersion ? `${PACKAGE_NAME}@${specificVersion}` : PACKAGE_NAME;
    const packageManager = process.env.PACKAGE_MANAGER || "npm";
    await execAsync9(`${packageManager} install -g ${packageSpec}`, {
      cwd: homedir4(),
      timeout: 120000
    });
    return "success";
  } catch (error) {
    console.error("\u5B89\u88C5\u5931\u8D25:", error);
    return "install_failed";
  }
}
async function performUpdate() {
  const latestVersion = await getLatestVersion();
  if (!latestVersion) {
    return {
      version: null,
      status: "install_failed",
      notifications: ["\u65E0\u6CD5\u83B7\u53D6\u6700\u65B0\u7248\u672C\u4FE1\u606F"]
    };
  }
  if (compareVersions(latestVersion, CURRENT_VERSION) <= 0) {
    return {
      version: CURRENT_VERSION,
      status: "up_to_date",
      notifications: ["\u5DF2\u662F\u6700\u65B0\u7248\u672C\uFF0C\u65E0\u9700\u66F4\u65B0"]
    };
  }
  const status = await installGlobalPackage(latestVersion);
  return {
    version: latestVersion,
    status,
    notifications: status === "success" ? [`\u6210\u529F\u66F4\u65B0\u5230\u7248\u672C ${latestVersion}`] : undefined
  };
}
function getUpdateInfo() {
  return `
\uD83D\uDD04 qoocode \u66F4\u65B0\u4FE1\u606F

\u5F53\u524D\u7248\u672C: ${CURRENT_VERSION}
npm \u5305\u540D: ${PACKAGE_NAME}

\u66F4\u65B0\u547D\u4EE4:
  npm update -g ${PACKAGE_NAME}
  # \u6216
  bun update -g ${PACKAGE_NAME}

\u68C0\u67E5\u66F4\u65B0:
  npm view ${PACKAGE_NAME}@latest version
`;
}

