// src/services/remote/remoteSessionService.ts
import { EventEmitter as EventEmitter6 } from "events";
import { spawn as spawn4 } from "child_process";
import * as fs3 from "fs";

class RemoteSessionService extends EventEmitter6 {
  sessions = new Map;
  processes = new Map;
  messageQueue = new Map;
  async createSession(config) {
    const sessionId = this.generateSessionId();
    const session = {
      id: sessionId,
      config,
      status: "pending",
      createdAt: new Date
    };
    this.sessions.set(sessionId, session);
    this.messageQueue.set(sessionId, []);
    try {
      await this.initializeBackend(session);
      session.status = "active";
      this.sessions.set(sessionId, session);
      this.emit("session:created", session);
      this.emitMessage({
        type: "status",
        sessionId,
        data: "active",
        timestamp: new Date
      });
      return session;
    } catch (error) {
      session.status = "error";
      this.sessions.set(sessionId, session);
      this.emitMessage({
        type: "error",
        sessionId,
        data: error instanceof Error ? error.message : "Unknown error",
        timestamp: new Date
      });
      throw error;
    }
  }
  async initializeBackend(session) {
    const { config } = session;
    if (config.backend === "tmux") {
      await this.initializeTmux(session);
    } else if (config.backend === "iterm2") {
      await this.initializeITerm2(session);
    }
  }
  async initializeTmux(session) {
    const { config, id } = session;
    const sessionName = config.sessionName || `qoocode-${id}`;
    const socketPath = `/tmp/qoocode-${id}.sock`;
    await this.execCommand("tmux", [
      "-L",
      `qoocode-${id}`,
      "new-session",
      "-d",
      "-s",
      sessionName,
      "-c",
      config.workingDirectory || process.cwd()
    ]);
    if (config.size) {
      await this.execCommand("tmux", [
        "-L",
        `qoocode-${id}`,
        "resize-window",
        "-t",
        sessionName,
        "-x",
        config.size.width.toString(),
        "-y",
        config.size.height.toString()
      ]);
    }
    session.socketPath = socketPath;
    session.processId = await this.getTmuxPid(sessionName);
  }
  async initializeITerm2(session) {
    const { config, id } = session;
    const scriptPath = `/tmp/qoocode-iterm-${id}.sh`;
    const script = `#!/bin/bash
osascript -e 'tell application "iTerm2"
  activate
  create window with default profile
  tell current session of current window
    write text "cd ${config.workingDirectory || process.cwd()}"
  end tell
end tell'`;
    fs3.writeFileSync(scriptPath, script);
    fs3.chmodSync(scriptPath, "755");
    const proc = spawn4("/bin/bash", [scriptPath], {
      env: { ...process.env, ...config.environment },
      detached: true
    });
    session.processId = proc.pid;
    this.processes.set(id, proc);
  }
  async sendInput(sessionId, input) {
    const session = this.sessions.get(sessionId);
    if (!session) {
      throw new Error(`Session ${sessionId} not found`);
    }
    if (session.status !== "active") {
      throw new Error(`Session ${sessionId} is not active`);
    }
    const { config } = session;
    if (config.backend === "tmux") {
      await this.execCommand("tmux", [
        "-L",
        `qoocode-${sessionId}`,
        "send-keys",
        "-t",
        config.sessionName,
        input,
        "Enter"
      ]);
    }
    this.emitMessage({
      type: "input",
      sessionId,
      data: input,
      timestamp: new Date
    });
  }
  async resizeSession(sessionId, width, height) {
    const session = this.sessions.get(sessionId);
    if (!session) {
      throw new Error(`Session ${sessionId} not found`);
    }
    const { config } = session;
    if (config.backend === "tmux") {
      await this.execCommand("tmux", [
        "-L",
        `qoocode-${sessionId}`,
        "resize-window",
        "-t",
        config.sessionName,
        "-x",
        width.toString(),
        "-y",
        height.toString()
      ]);
    }
    this.emitMessage({
      type: "resize",
      sessionId,
      data: { width, height },
      timestamp: new Date
    });
  }
  async captureOutput(sessionId, lines = 100) {
    const session = this.sessions.get(sessionId);
    if (!session) {
      throw new Error(`Session ${sessionId} not found`);
    }
    const { config } = session;
    if (config.backend === "tmux") {
      const output = await this.execCommand("tmux", [
        "-L",
        `qoocode-${sessionId}`,
        "capture-pane",
        "-t",
        config.sessionName,
        "-p",
        "-S",
        `-${lines}`
      ]);
      return output;
    }
    return "";
  }
  async attachSession(sessionId) {
    const session = this.sessions.get(sessionId);
    if (!session) {
      throw new Error(`Session ${sessionId} not found`);
    }
    const { config } = session;
    if (config.backend === "tmux") {
      const proc = spawn4("tmux", [
        "-L",
        `qoocode-${sessionId}`,
        "pipe-pane",
        "-t",
        config.sessionName,
        "cat"
      ]);
      this.processes.set(`${sessionId}-pipe`, proc);
      const self2 = this;
      return async function* () {
        for await (const chunk2 of proc.stdout) {
          const line = chunk2.toString();
          self2.emitMessage({
            type: "output",
            sessionId,
            data: line,
            timestamp: new Date
          });
          yield line;
        }
      }();
    }
    return async function* () {}();
  }
  async disconnectSession(sessionId) {
    const session = this.sessions.get(sessionId);
    if (!session) {
      return;
    }
    session.status = "disconnected";
    this.sessions.set(sessionId, session);
    const proc = this.processes.get(sessionId);
    if (proc) {
      proc.kill();
      this.processes.delete(sessionId);
    }
    const pipeProc = this.processes.get(`${sessionId}-pipe`);
    if (pipeProc) {
      pipeProc.kill();
      this.processes.delete(`${sessionId}-pipe`);
    }
    this.emitMessage({
      type: "status",
      sessionId,
      data: "disconnected",
      timestamp: new Date
    });
  }
  async deleteSession(sessionId) {
    await this.disconnectSession(sessionId);
    const session = this.sessions.get(sessionId);
    if (!session) {
      return;
    }
    const { config } = session;
    if (config.backend === "tmux") {
      await this.execCommand("tmux", [
        "-L",
        `qoocode-${sessionId}`,
        "kill-session",
        "-t",
        config.sessionName
      ]).catch(() => {});
    }
    this.sessions.delete(sessionId);
    this.messageQueue.delete(sessionId);
    this.emit("session:deleted", sessionId);
  }
  listSessions() {
    return Array.from(this.sessions.values());
  }
  getSession(sessionId) {
    return this.sessions.get(sessionId);
  }
  getMessages(sessionId) {
    return this.messageQueue.get(sessionId) || [];
  }
  clearMessages(sessionId) {
    this.messageQueue.set(sessionId, []);
  }
  execCommand(command, args) {
    return new Promise((resolve3, reject2) => {
      const proc = spawn4(command, args);
      let stdout = "";
      let stderr = "";
      proc.stdout?.on("data", (data) => {
        stdout += data.toString();
      });
      proc.stderr?.on("data", (data) => {
        stderr += data.toString();
      });
      proc.on("close", (code) => {
        if (code === 0) {
          resolve3(stdout);
        } else {
          reject2(new Error(stderr || `Command exited with code ${code}`));
        }
      });
      proc.on("error", reject2);
    });
  }
  async getTmuxPid(sessionName) {
    try {
      const output = await this.execCommand("tmux", [
        "display-message",
        "-p",
        "#{session_pid}"
      ]);
      return parseInt(output.trim(), 10) || undefined;
    } catch {
      return;
    }
  }
  generateSessionId() {
    return `session-${Date.now()}-${Math.random().toString(36).substring(2, 9)}`;
  }
  emitMessage(message) {
    const queue = this.messageQueue.get(message.sessionId) || [];
    queue.push(message);
    this.messageQueue.set(message.sessionId, queue);
    this.emit("message", message);
  }
}
var remoteSessionService = null;
function getRemoteSessionService() {
  if (!remoteSessionService) {
    remoteSessionService = new RemoteSessionService;
  }
  return remoteSessionService;
}
async function createRemoteSession(config) {
  return getRemoteSessionService().createSession(config);
}

// src/commands/ultraplan/ultraplan.ts
var ultraplanSessions = new Map;
var ULTRAPLAN_USAGE = `
**Ultraplan Command**

Usage: \`/ultraplan [options] <prompt>\`

**Description:**
Ultraplan is an advanced multi-agent planning mode that uses our most powerful model (Opus) to create detailed, structured plans for complex tasks.

**Options:**
- \`-r, --remote\`     Create a remote session (Tmux/iTerm2)
- \`-p, --parallel\`   Enable parallel execution planning
- \`-v, --verbose\`    Show detailed analysis

**Features:**
- Advanced multi-agent planning
- Detailed step-by-step breakdown of complex tasks
- Interactive plan refinement and approval
- Parallel execution planning
- Resource estimation and timeline projections
- Remote session support (Tmux/iTerm2)
- Complexity analysis and timeline estimation
- Technology auto-detection

**Examples:**
\`\`\`
/ultraplan Build a full-stack e-commerce application
/ultraplan --remote --verbose Design a microservices architecture
/ultraplan --parallel Create a mobile app with React Native
\`\`\`

**Workflow:**
1. You provide a high-level task or problem
2. Ultraplan analyzes the requirements and creates a detailed plan
3. You can review, edit, and approve the plan
4. The approved plan can be executed step-by-step

**Requirements:**
- Requires user login (\`/login\`) for advanced model access
- Suitable for complex, multi-step projects
- Best for tasks requiring 10+ steps or multiple components

**Remote Sessions:**
- Uses Tmux (Linux/macOS) or iTerm2 (macOS) for background planning
- Sessions can be attached/detached for long-running plans
- View active sessions with \`/ultraplan list\`

---

You can also include "ultraplan" anywhere in your prompt to trigger this mode automatically.
`;
function generateUltraplan(task) {
  const templates = [
    {
      keywords: ["e-commerce", "shop", "store", "cart", "checkout"],
      plan: `
## E-commerce Application Plan

**Phase 1: Project Setup**
- Initialize project structure
- Set up development environment
- Configure build tools and dependencies

**Phase 2: Backend Development**
- Design database schema (products, users, orders)
- Implement REST API endpoints
- Add authentication and authorization
- Set up payment processing (Stripe integration)

**Phase 3: Frontend Development**
- Create React component structure
- Implement product listing and detail pages
- Build shopping cart functionality
- Add user authentication UI

**Phase 4: Testing & Deployment**
- Write unit and integration tests
- Set up CI/CD pipeline
- Deploy to production environment
- Monitor and optimize performance`
    },
    {
      keywords: ["dashboard", "analytics", "report", "chart", "graph"],
      plan: `
## Analytics Dashboard Plan

**Phase 1: Data Architecture**
- Design data collection strategy
- Set up database for metrics storage
- Implement data ingestion pipeline
- Create data transformation workflows

**Phase 2: Backend API**
- Build RESTful API for data access
- Implement aggregation and filtering
- Add real-time updates (WebSocket/SSE)
- Create data export functionality

**Phase 3: Frontend Visualization**
- Design responsive dashboard layout
- Implement chart components (bar, line, pie)
- Add interactive filters and controls
- Create data drill-down capabilities

**Phase 4: Advanced Features**
- Add user permissions and roles
- Implement scheduled reports
- Set up alerting and notifications
- Add custom metric configuration`
    },
    {
      keywords: ["api", "backend", "server", "rest", "graphql"],
      plan: `
## API Backend Plan

**Phase 1: Design & Architecture**
- Define API specifications (OpenAPI/Swagger)
- Design data models and relationships
- Plan authentication and security
- Set up project structure

**Phase 2: Core Implementation**
- Implement main endpoints (CRUD operations)
- Add request validation and error handling
- Set up database integration
- Implement business logic

**Phase 3: Advanced Features**
- Add rate limiting and throttling
- Implement caching layer
- Set up logging and monitoring
- Add API documentation

**Phase 4: Testing & Deployment**
- Write comprehensive test suite
- Set up CI/CD pipeline
- Deploy to cloud platform
- Configure monitoring and alerts`
    },
    {
      keywords: ["mobile", "app", "ios", "android", "react native"],
      plan: `
## Mobile Application Plan

**Phase 1: Project Setup**
- Choose framework (React Native, Flutter, etc.)
- Set up development environment
- Configure platform-specific settings
- Design app architecture

**Phase 2: Core Features**
- Implement main app screens
- Add navigation and routing
- Set up state management
- Implement API integration

**Phase 3: Platform Specifics**
- Add iOS-specific features
- Implement Android-specific functionality
- Handle device permissions
- Optimize for different screen sizes

**Phase 4: Polish & Deployment**
- Add animations and transitions
- Implement offline capabilities
- Set up app store deployment
- Add analytics and crash reporting`
    }
  ];
  const taskLower = task.toLowerCase();
  let selectedTemplate = templates[0];
  for (const template2 of templates) {
    if (template2.keywords.some((keyword) => taskLower.includes(keyword))) {
      selectedTemplate = template2;
      break;
    }
  }
  return selectedTemplate.plan;
}
async function createUltraplanSession(task) {
  const sessionId = `ultraplan-${Date.now()}`;
  const isMac = process.platform === "darwin";
  const backend = isMac ? "iterm2" : "tmux";
  const config = {
    backend,
    sessionName: `ultraplan-${sessionId}`,
    workingDirectory: process.cwd(),
    size: { width: 120, height: 40 }
  };
  try {
    const session = await createRemoteSession(config);
    ultraplanSessions.set(sessionId, {
      sessionId: session.id,
      task,
      phase: "planning"
    });
    return sessionId;
  } catch {
    return `local-${sessionId}`;
  }
}
function getActiveSessions() {
  return Array.from(ultraplanSessions.values());
}
var call = async (onDone, context, args) => {
  const blurb = args.trim();
  const options = blurb.match(/--(\w+)(?:\s+([^\s]+))?/g) || [];
  const isRemote = blurb.includes("--remote") || blurb.includes("-r");
  const isVerbose = blurb.includes("--verbose") || blurb.includes("-v");
  const isParallel = blurb.includes("--parallel") || blurb.includes("-p");
  const task = blurb.replace(/--\w+(?:\s+[^\s]+)?/g, "").trim();
  if (!task) {
    onDone(ULTRAPLAN_USAGE, { display: "system" });
    return null;
  }
  let sessionInfo = "";
  if (isRemote) {
    try {
      const sessionId = await createUltraplanSession(task);
      sessionInfo = `
**Remote Session Created:**
- Session ID: ${sessionId}
- Backend: ${process.platform === "darwin" ? "iTerm2" : "Tmux"}
- Status: Active
- Type: /plan --remote or /ultraplan --remote
`;
    } catch {
      sessionInfo = `
\u26A0\uFE0F Remote session creation failed, using local mode
`;
    }
  }
  const plan = generateUltraplan(task);
  let message = `
# \uD83D\uDE80 Ultraplan Created

**Task:** ${task}
${sessionInfo}
**Status:** Plan generated successfully
${isVerbose ? `
**Options:**
- Remote: ${isRemote}
- Parallel: ${isParallel}
- Verbose: ${isVerbose}` : ""}

**Plan Summary:**
${plan}

---

**Planning Modes:**

1. **Interactive Planning**: Use \`/plan\` to enter interactive mode
2. **Remote Session**: Use \`/ultraplan --remote ${task}\` for remote planning
3. **Parallel Execution**: Use \`/ultraplan --parallel ${task}\` for parallel planning

**Active Sessions:**
${getActiveSessions().length > 0 ? getActiveSessions().map((s) => `- ${s.sessionId}: ${s.task} (${s.phase})`).join(`
`) : "No active sessions"}

**Next Steps:**
1. Review the plan above
2. Use \`/plan\` for interactive planning
${isRemote ? `3. The plan is running in a remote session
` : ""}4. Execute with \`/exec\` when ready

**Estimated Complexity:** ${estimateComplexity(task)}
**Recommended Approach:** ${isParallel ? "Multi-agent parallel execution" : "Sequential execution"}
**Timeline:** ${estimateTimeline(task)}

---

*Note: Ultraplan uses advanced multi-agent planning for complex tasks.*`;
  if (isVerbose) {
    message += `

**Detailed Analysis:**

${analyzeTask(task)}
`;
  }
  onDone(message, {
    display: "system"
  });
  return null;
};
function estimateComplexity(task) {
  const taskLower = task.toLowerCase();
  const complexityIndicators = {
    high: ["microservice", "distributed", "blockchain", "ml", "ai", "machine learning", "kubernetes", "aws", "gcp", "multi-tenant"],
    medium: ["api", "database", "frontend", "backend", "authentication", "payment", "integration"],
    low: ["simple", "basic", "static", "landing page", "blog"]
  };
  for (const [level, keywords] of Object.entries(complexityIndicators)) {
    if (keywords.some((k) => taskLower.includes(k))) {
      return level.charAt(0).toUpperCase() + level.slice(1);
    }
  }
  return "Medium";
}
function estimateTimeline(task) {
  const complexity = estimateComplexity(task);
  const timelines = {
    High: "1-4 weeks",
    Medium: "3-7 days",
    Low: "1-2 days"
  };
  return timelines[complexity] || "1 week";
}
function analyzeTask(task) {
  const sections = [];
  const techPatterns = {
    Frontend: [/react/i, /vue/i, /angular/i, /svelte/i, /next\.?js/i, /nuxt/i],
    Backend: [/node\.?js/i, /python/i, /go/i, /rust/i, /java/i, /c#|\\.net/i],
    Database: [/postgresql/i, /mysql/i, /mongodb/i, /redis/i, /sqlite/i],
    Cloud: [/aws/i, /gcp/i, /azure/i, /kubernetes/i, /docker/i]
  };
  sections.push("**Detected Technologies:**");
  let detectedAny = false;
  for (const [category, patterns] of Object.entries(techPatterns)) {
    const found = patterns.filter((p) => p.test(task));
    if (found.length > 0) {
      sections.push(`- ${category}: ${found.map((p) => p.source.replace(/[()]/g, "")).join(", ")}`);
      detectedAny = true;
    }
  }
  if (!detectedAny) {
    sections.push("- None detected (will auto-detect during implementation)");
  }
  sections.push(`
**Recommended Phases:**`);
  sections.push("1. Requirements Analysis & Design");
  sections.push("2. Project Setup & Architecture");
  sections.push("3. Core Features Implementation");
  sections.push("4. Testing & Quality Assurance");
  sections.push("5. Deployment & Documentation");
  return sections.join(`
`);
}
var ultraplan_default = {
  type: "local",
  name: "ultraplan",
  description: "Advanced multi-agent planning mode for complex tasks",
  argumentHint: "<prompt>",
  isEnabled: () => true,
  execute(args) {
    const parsedArgs = parseArgs(args || "");
    if (parsedArgs.options.help) {
      return ULTRAPLAN_USAGE;
    }
    const options = {
      remote: parsedArgs.options.remote || false,
      parallel: parsedArgs.options.parallel || false,
      verbose: parsedArgs.options.verbose || false
    };
    return `__ULTRAPLAN__:${JSON.stringify({
      prompt: parsedArgs.prompt,
      options
    })}`;
  },
  load: () => Promise.resolve({
    call
  })
};

// src/commands/speech/speech.ts
init_speechService();
var speechService = null;
function getSpeechService() {
  if (!speechService) {
    speechService = new SpeechService;
  }
  return speechService;
}
var speechCommand = {
  name: "speech",
  aliases: ["voice", "tts", "stt"],
  description: "\u8BED\u97F3\u670D\u52A1 - \u6587\u672C\u8F6C\u8BED\u97F3\u548C\u8BED\u97F3\u8F6C\u6587\u672C",
  type: "local",
  execute(args) {
    const parts = (args || "").trim().split(/\s+/);
    const action = parts[0]?.toLowerCase() || "help";
    const restArgs = parts.slice(1).join(" ");
    switch (action) {
      case "speak":
      case "say":
        return handleSpeak(restArgs);
      case "listen":
      case "start":
        return handleListen();
      case "stop":
        return handleStop();
      case "voices":
        return handleVoices();
      case "status":
        return handleStatus();
      case "config":
        return handleConfig(restArgs);
      case "help":
      default:
        return showHelp2();
    }
  }
};
function handleSpeak(text) {
  if (!text) {
    return `Usage: /speech speak <text>

Example: /speech speak Hello, how are you?`;
  }
  const service = getSpeechService();
  if (!service.isTtsSupported()) {
    return `Text-to-Speech not supported in this environment.
    
You can try:
- Windows: Install PowerShell with System.Speech
- macOS: Use the built-in 'say' command
- Linux: Install espeak (sudo apt install espeak)`;
  }
  service.speak(text);
  return `\uD83D\uDD0A Speaking: "${text.substring(0, 80)}${text.length > 80 ? "..." : ""}"`;
}
function handleListen() {
  const service = getSpeechService();
  if (!service.isSttSupported()) {
    return `Speech recognition not supported in this environment.
    
You can try:
- Use Chrome browser (best support)
- Enable Web Speech API in browser settings
- Use Whisper API with /speech transcribe <file>`;
  }
  service.startListening();
  return `\uD83C\uDFA4 Listening for speech... (say "stop" or press Ctrl+C to stop)

Tip: Speak clearly and wait for the result.`;
}
function handleStop() {
  const service = getSpeechService();
  service.stop();
  service.abortListening();
  const transcript = service.getTranscript();
  if (transcript.final) {
    return `\u23F9\uFE0F Stopped listening.

You said: "${transcript.final}"`;
  }
  return "\u23F9\uFE0F Stopped all speech operations.";
}
function handleVoices() {
  const service = getSpeechService();
  if (!service.isTtsSupported()) {
    return "Speech synthesis not supported in this environment.";
  }
  const voices = service.getAvailableVoices();
  if (voices.length === 0) {
    return "No voices available. Voices may still be loading...";
  }
  const byLanguage = new Map;
  for (const voice of voices) {
    const lang = voice.lang;
    if (!byLanguage.has(lang)) {
      byLanguage.set(lang, []);
    }
    byLanguage.get(lang).push(voice);
  }
  const lines = [
    "\uD83D\uDDE3\uFE0F Available Voices:",
    "",
    ...Array.from(byLanguage.entries()).flatMap(([lang, langVoices]) => [
      `  ${lang}:`,
      ...langVoices.map((v) => `    ${v.name}${v.default ? " \u2605" : ""}`),
      ""
    ]),
    `Total: ${voices.length} voices`,
    "",
    'Use: /speech config --ttsVoice "<voice-name>"'
  ];
  return lines.join(`
`);
}
function handleStatus() {
  const service = getSpeechService();
  const ttsSupported = service.isTtsSupported();
  const sttSupported = service.isSttSupported();
  const isSpeaking = service.isSpeaking();
  const isListening = service.isListening();
  const config = service.getConfig();
  const lines = [
    "\uD83C\uDF99\uFE0F Speech Service Status",
    "========================",
    "",
    `  Text-to-Speech (TTS): ${ttsSupported ? "\u2705 Supported" : "\u274C Not Supported"}`,
    `  Speech-to-Text (STT): ${sttSupported ? "\u2705 Supported" : "\u274C Not Supported"}`,
    `  Currently Speaking: ${isSpeaking ? "\uD83D\uDD0A Yes" : "\uD83D\uDD07 No"}`,
    `  Currently Listening: ${isListening ? "\uD83C\uDFA4 Yes" : "\uD83C\uDFA4 No"}`,
    "",
    "  Configuration:",
    `    TTS Language: ${config.ttsLanguage}`,
    `    TTS Rate: ${config.ttsRate}`,
    `    TTS Pitch: ${config.ttsPitch}`,
    `    TTS Volume: ${config.ttsVolume}`,
    `    STT Language: ${config.sttLanguage}`,
    `    Whisper API: ${config.useWhisper ? "\u2705 Enabled" : "\u274C Disabled"}`,
    ""
  ];
  return lines.join(`
`);
}
function handleConfig(args) {
  if (!args) {
    return showConfigHelp();
  }
  const config = {};
  const parts = args.split(/\s+/);
  for (const part of parts) {
    const [key, value] = part.split("=");
    if (!key || !value)
      continue;
    switch (key.replace(/^--/, "")) {
      case "tts-language":
      case "ttsLanguage":
        config.ttsLanguage = value;
        break;
      case "tts-rate":
      case "ttsRate":
        config.ttsRate = parseFloat(value);
        break;
      case "tts-pitch":
      case "ttsPitch":
        config.ttsPitch = parseFloat(value);
        break;
      case "tts-volume":
      case "ttsVolume":
        config.ttsVolume = parseFloat(value);
        break;
      case "tts-voice":
      case "ttsVoice":
        config.ttsVoice = value.replace(/^["']|["']$/g, "");
        break;
      case "stt-language":
      case "sttLanguage":
        config.sttLanguage = value;
        break;
      case "whisper":
        config.useWhisper = value === "true" || value === "1";
        break;
    }
  }
  const service = getSpeechService();
  service.updateConfig(config);
  return `\u2705 Speech configuration updated:

${JSON.stringify(config, null, 2)}

Use /speech status to verify changes.`;
}
function showHelp2() {
  return `\uD83C\uDF99\uFE0F Speech Commands
====================

Usage: /speech <command> [options]

Commands:
  /speech speak <text>    - Read text aloud (TTS)
  /speech listen          - Start speech recognition (STT)
  /speech stop            - Stop speaking or listening
  /speech voices          - List available TTS voices
  /speech status          - Show speech service status
  /speech config <opts>   - Update speech configuration

Configuration Options:
  --tts-language=<lang>   - Set TTS language (e.g., zh-CN, en-US)
  --tts-rate=<rate>       - Set speaking rate (0.1-10, default: 1.0)
  --tts-pitch=<pitch>     - Set pitch (0-2, default: 1.0)
  --tts-volume=<vol>      - Set volume (0-1, default: 1.0)
  --tts-voice=<name>      - Set specific voice
  --stt-language=<lang>   - Set STT language
  --whisper=true|false    - Enable/disable Whisper API

Examples:
  /speech speak Hello, how are you today?
  /speech speak Bonjour, comment allez-vous?
  /speech listen
  /speech voices
  /speech config --tts-rate=0.8 --tts-pitch=1.2`;
}
function showConfigHelp() {
  return `\uD83C\uDF99\uFE0F Speech Configuration
=========================

Usage: /speech config <options>

Options:
  --tts-language=<lang>    Language for text-to-speech (default: zh-CN)
  --tts-rate=<rate>        Speaking rate 0.1-10 (default: 1.0)
  --tts-pitch=<pitch>      Pitch 0-2 (default: 1.0)
  --tts-volume=<vol>       Volume 0-1 (default: 1.0)
  --tts-voice=<name>       Use specific voice (use /speech voices to list)
  --stt-language=<lang>    Language for speech recognition (default: zh-CN)
  --whisper=true|false     Use Whisper API for transcription

Examples:
  /speech config --tts-language=en-US --tts-rate=1.2
  /speech config --tts-voice="Microsoft David"
  /speech config --whisper=true

Note: Use /speech voices to see available voices in your system.`;
}

